// ── Audio FX ──
const AC = typeof window !== "undefined" ? (window.AudioContext || (window as any).webkitAudioContext) : null;
let ac = null;
const gac = () => { if (!ac && AC) ac = new AC(); return ac; };
const sfx = (t) => {
  const c = gac(); if (!c) return; const n = c.currentTime;
  if (t === "correct") {
    [587, 740, 880].forEach((f, i) => { const o = c.createOscillator(), g = c.createGain(); o.type = "triangle"; o.connect(g); g.connect(c.destination); o.frequency.setValueAtTime(f, n + i * 0.07); g.gain.setValueAtTime(0.18, n + i * 0.07); g.gain.exponentialRampToValueAtTime(0.001, n + i * 0.07 + 0.2); o.start(n + i * 0.07); o.stop(n + i * 0.07 + 0.2); });
  } else if (t === "wrong") {
    const o = c.createOscillator(), g = c.createGain(); o.type = "sawtooth"; o.connect(g); g.connect(c.destination); o.frequency.setValueAtTime(160, n); o.frequency.linearRampToValueAtTime(100, n + 0.2); g.gain.setValueAtTime(0.12, n); g.gain.exponentialRampToValueAtTime(0.001, n + 0.25); o.start(n); o.stop(n + 0.25);
  } else if (t === "goal") {
    [523, 659, 784, 1047, 1319, 1568].forEach((f, i) => { const o = c.createOscillator(), g = c.createGain(); o.type = "triangle"; o.connect(g); g.connect(c.destination); o.frequency.setValueAtTime(f, n + i * 0.13); g.gain.setValueAtTime(0.25, n + i * 0.13); g.gain.exponentialRampToValueAtTime(0.001, n + i * 0.13 + 0.7); o.start(n + i * 0.13); o.stop(n + i * 0.13 + 0.7); });
    // crowd roar
    const noise = c.createBufferSource(); const buf = c.createBuffer(1, c.sampleRate * 2, c.sampleRate); const data = buf.getChannelData(0); for (let i = 0; i < data.length; i++) data[i] = (Math.random() * 2 - 1) * 0.08; noise.buffer = buf; const g2 = c.createGain(); const bp = c.createBiquadFilter(); bp.type = "bandpass"; bp.frequency.value = 800; bp.Q.value = 0.5; noise.connect(bp); bp.connect(g2); g2.connect(c.destination); g2.gain.setValueAtTime(0, n); g2.gain.linearRampToValueAtTime(0.15, n + 0.3); g2.gain.linearRampToValueAtTime(0.1, n + 1.5); g2.gain.exponentialRampToValueAtTime(0.001, n + 3); noise.start(n); noise.stop(n + 3);
  } else if (t === "whistle") {
    [2600, 3200, 2600].forEach((f, i) => { const o = c.createOscillator(), g = c.createGain(); o.type = "sine"; o.connect(g); g.connect(c.destination); o.frequency.setValueAtTime(f, n + i * 0.12); g.gain.setValueAtTime(0.1, n + i * 0.12); g.gain.exponentialRampToValueAtTime(0.001, n + 0.5); o.start(n); o.stop(n + 0.5); });
  } else if (t === "tap") {
    const o = c.createOscillator(), g = c.createGain(); o.connect(g); g.connect(c.destination); o.frequency.setValueAtTime(800, n); g.gain.setValueAtTime(0.06, n); g.gain.exponentialRampToValueAtTime(0.001, n + 0.05); o.start(n); o.stop(n + 0.05);
  }
};

