// ── Exercise type by rep (easy → hard, repeating) ──
// 0-7: listen, 8-14: nextWord, 15-21: blanks, 22-27: order, 28-29: order
const getExType = (rep) => {
  if (rep < 8) return "listen";
  if (rep < 15) return "nextWord";
  if (rep < 22) return "blanks";
  return "order";
};
