// ── EXERCISES ──

// 1. Listen & Repeat (with audio button)
function ExListen({ ayah, ayahGlobalNum, onDone }) {
  const [audioState, setAudioState] = useState("idle"); // idle, loading, playing, error
  const audioRef = useRef(null);
  const timeoutRef = useRef(null);

  const playAudio = () => {
    if (!ayahGlobalNum) { setAudioState("error"); return; }
    if (audioRef.current) { audioRef.current.pause(); audioRef.current = null; }
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    
    setAudioState("loading");
    const url = `https://cdn.islamic.network/quran/audio/128/ar.alafasy/${ayahGlobalNum}.mp3`;
    const a = new Audio();
    audioRef.current = a;
    
    a.oncanplaythrough = () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      setAudioState("playing");
      a.play().catch(() => setAudioState("error"));
    };
    a.onended = () => setAudioState("idle");
    a.onerror = () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      setAudioState("error");
    };
    
    timeoutRef.current = setTimeout(() => setAudioState("error"), 6000);
    
    a.src = url;
    a.load();
  };

  useEffect(() => () => {
    if (audioRef.current) { audioRef.current.pause(); audioRef.current = null; }
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
  }, []);

  const isPlaying = audioState === "playing";
  const isLoading = audioState === "loading";
  const isError = audioState === "error";

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16, animation: "fadeUp 0.35s both" }}>
      <div style={{ textAlign: "center", color: "#5a5a6a", fontSize: 15, fontWeight: 600 }}>🔊 استمع للآية ثم ردّدها بصوتك</div>
      <AyahBox text={ayah} />
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 8 }}>
        <button onClick={playAudio} disabled={isPlaying || isLoading}
          style={{
            width: 80, height: 80, borderRadius: "50%",
            background: isPlaying ? "linear-gradient(135deg, #1565C0, #0D47A1)" : isError ? "linear-gradient(135deg, #C62828, #B71C1C)" : "linear-gradient(135deg, #0D7C3D, #1B5E20)",
            border: "4px solid rgba(255,255,255,0.3)", cursor: isPlaying ? "default" : "pointer", fontSize: 36,
            boxShadow: "0 6px 24px rgba(0,0,0,0.2)",
            animation: isPlaying ? "pulse 1s infinite" : isLoading ? "pulse 0.6s infinite" : "none",
            transition: "all 0.3s",
            display: "flex", alignItems: "center", justifyContent: "center",
          }}>
          {isLoading ? "⏳" : isPlaying ? "🔊" : isError ? "🔇" : "▶️"}
        </button>
        <p style={{ textAlign: "center", fontSize: 13, color: isError ? "#C62828" : "#999" }}>
          {isLoading ? "جاري التحميل..." : isPlaying ? "🔊 جاري التشغيل..." : isError ? "⚠️ الصوت غير متوفر — اقرأ الآية بنفسك" : "اضغط لسماع الشيخ المشاري العفاسي"}
        </p>
      </div>
      <Btn onClick={() => { sfx("correct"); onDone(1, 1); }} color="#0D7C3D" full>✅ رددت الآية</Btn>
    </div>
  );
}

// 2. What's the next word? (MCQ)
function ExNextWord({ ayah, allAyahs, onDone }) {
  const words = useMemo(() => ayah.split(" "), [ayah]);
  const cutIdx = useMemo(() => Math.max(1, Math.floor(Math.random() * (words.length - 1)) + 1), [words]);
  const shown = words.slice(0, cutIdx).join(" ");
  const correctWord = words[cutIdx];
  const options = useMemo(() => {
    if (!correctWord) return [];
    const pool = [...new Set(allAyahs.flatMap(a => a.split(" ")).filter(w => w !== correctWord && w.length > 1))];
    return shuffle([correctWord, ...shuffle(pool).slice(0, Math.min(3, pool.length))]);
  }, [correctWord, allAyahs]);
  const [picked, setPicked] = useState(null);
  const [err, setErr] = useState(false);

  if (!correctWord) { setTimeout(() => onDone(1, 1), 100); return null; }

  const pick = (w) => {
    if (picked) return;
    if (w === correctWord) {
      sfx("correct"); setPicked(w);
      setTimeout(() => onDone(1, 1), 500);
    } else {
      sfx("wrong"); setErr(true); setTimeout(() => setErr(false), 500);
    }
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 14, animation: "fadeUp 0.35s both" }}>
      <div style={{ textAlign: "center", color: "#5a5a6a", fontSize: 15, fontWeight: 600 }}>🤔 ما الكلمة التالية؟</div>
      <div style={{
        background: "linear-gradient(135deg, #FFFDE7, #FFF8E1)", borderRadius: 20,
        padding: "18px 22px", border: "2px solid rgba(249,168,37,0.35)", direction: "rtl", textAlign: "center",
      }}>
        <p style={{ fontFamily: "'Amiri Quran',serif", fontSize: 22, lineHeight: 2.1, color: "#1a1a2e" }}>
          {shown} <span style={{ color: "#E65100", fontWeight: 900, fontSize: 26 }}>؟</span>
        </p>
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {options.map((o, i) => (
          <button key={i} onClick={() => pick(o)} disabled={!!picked}
            style={{
              padding: "13px 20px", borderRadius: 14, fontSize: 19, fontFamily: "'Amiri Quran',serif",
              direction: "rtl", textAlign: "right",
              background: picked === o && o === correctWord ? "#E8F5E9" : picked && o === correctWord ? "#E8F5E9" : "#fff",
              border: picked === o && o === correctWord ? "3px solid #0D7C3D" : err ? "3px solid #eee" : "3px solid #eee",
              cursor: picked ? "default" : "pointer", transition: "all 0.2s",
              animation: err && !picked ? "shake 0.3s" : "",
            }}>{o}</button>
        ))}
      </div>
    </div>
  );
}

// 3. Fill the blank
function ExBlanks({ ayah, allAyahs, onDone }) {
  const words = useMemo(() => ayah.split(" "), [ayah]);
  const blankIdx = useMemo(() => {
    const avail = words.map((_, i) => i).filter(i => words[i].length > 2);
    return avail.length > 0 ? avail[Math.floor(Math.random() * avail.length)] : 0;
  }, [words]);
  const correctWord = words[blankIdx];
  const options = useMemo(() => {
    const pool = [...new Set(allAyahs.flatMap(a => a.split(" ")).filter(w => w !== correctWord && w.length > 1))];
    return shuffle([correctWord, ...shuffle(pool).slice(0, 2)]);
  }, [correctWord, allAyahs]);
  const [picked, setPicked] = useState(null);
  const [err, setErr] = useState(false);

  const pick = (w) => {
    if (picked) return;
    if (w === correctWord) {
      sfx("correct"); setPicked(w);
      setTimeout(() => onDone(1, 1), 500);
    } else { sfx("wrong"); setErr(true); setTimeout(() => setErr(false), 500); }
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 14, animation: "fadeUp 0.35s both" }}>
      <div style={{ textAlign: "center", color: "#5a5a6a", fontSize: 15, fontWeight: 600 }}>✨ أكمل الكلمة المخفية</div>
      <div style={{
        background: "linear-gradient(135deg, #FFFDE7, #FFF8E1)", borderRadius: 20,
        padding: "18px 22px", border: "2px solid rgba(249,168,37,0.35)", direction: "rtl", textAlign: "center",
      }}>
        <p style={{ fontFamily: "'Amiri Quran',serif", fontSize: 22, lineHeight: 2.1, color: "#1a1a2e" }}>
          {words.map((w, i) => {
            if (i === blankIdx) {
              if (picked) return <span key={i} style={{ color: "#0D7C3D", fontWeight: 900 }}>{picked} </span>;
              return <span key={i} style={{ display: "inline-block", background: "rgba(230,81,0,0.1)", borderRadius: 8, padding: "2px 12px", borderBottom: "3px solid #E65100", margin: "0 4px", minWidth: 50 }}>
                <span style={{ color: "#E65100", fontWeight: 900 }}>؟</span>
              </span>;
            }
            return <span key={i}>{w} </span>;
          })}
        </p>
      </div>
      <div style={{ display: "flex", gap: 10, justifyContent: "center", flexWrap: "wrap" }}>
        {options.map((o, i) => (
          <Btn key={i} onClick={() => pick(o)} color={picked && o === correctWord ? "#0D7C3D" : "#1565C0"}
            disabled={!!picked}
            style={{ fontSize: 19, fontFamily: "'Amiri Quran',serif", animation: err && !picked ? "shake 0.3s" : "" }}>{o}</Btn>
        ))}
      </div>
    </div>
  );
}

// 4. Word order (drag-like tap)
function ExOrder({ ayah, onDone }) {
  const words = useMemo(() => ayah.split(" "), [ayah]);
  const shuffled = useMemo(() => shuffle(words.map((w, i) => ({ w, i }))), [words]);
  const [placed, setPlaced] = useState([]);
  const [err, setErr] = useState(false);

  const pick = (item) => {
    if (item.i === placed.length) {
      sfx("correct"); const np = [...placed, item]; setPlaced(np); setErr(false);
      if (np.length === words.length) setTimeout(() => onDone(1, 1), 500);
    } else { sfx("wrong"); setErr(true); setTimeout(() => setErr(false), 500); }
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 14, animation: "fadeUp 0.35s both" }}>
      <div style={{ textAlign: "center", color: "#5a5a6a", fontSize: 15, fontWeight: 600 }}>⚡ رتّب كلمات الآية</div>
      <div style={{
        background: "rgba(255,255,255,0.7)", borderRadius: 16, padding: 14, minHeight: 52,
        display: "flex", flexWrap: "wrap", gap: 8, justifyContent: "center", direction: "rtl",
        border: "2px dashed #0D7C3D",
      }}>
        {placed.length === 0 && <span style={{ color: "#ccc", fontSize: 14, alignSelf: "center" }}>ابدأ بأول كلمة...</span>}
        {placed.map((item, i) => (
          <span key={i} style={{
            background: "#0D7C3D", color: "#fff", padding: "7px 14px", borderRadius: 10,
            fontSize: 18, fontFamily: "'Amiri Quran',serif", animation: "pop 0.2s both",
          }}>{item.w}</span>
        ))}
      </div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 8, justifyContent: "center", direction: "rtl" }}>
        {shuffled.filter(s => !placed.find(p => p.i === s.i)).map((item, i) => (
          <button key={i} onClick={() => pick(item)} style={{
            background: "#fff", border: err ? "2px solid #C62828" : "2px solid #e0e0e0",
            padding: "9px 16px", borderRadius: 12, fontSize: 18, fontFamily: "'Amiri Quran',serif",
            cursor: "pointer", boxShadow: "0 2px 6px rgba(0,0,0,0.04)", transition: "all 0.15s",
            animation: err ? "shake 0.3s" : "",
          }}>{item.w}</button>
        ))}
      </div>
    </div>
  );
}

// ================================================================
// MAIN APP
// ================================================================
export default function Miqdam() {
  const [view, setView] = useState("welcome");
  // Setup
  const [setupStep, setSetupStep] = useState(0);
  const [pName, setPName] = useState("");
  const [tName, setTName] = useState("");
  const [jNum, setJNum] = useState(10);
  const [jCol, setJCol] = useState(0);
  const [bdg, setBdg] = useState(0);
  const [profile, setProfile] = useState(null);
  // Pick
  const [surahNum, setSurahNum] = useState(112);
  const [ayFrom, setAyFrom] = useState(1);
  const [ayTo, setAyTo] = useState(4);
  // Match
  const [ayahs, setAyahs] = useState([]);
  const [ayahGlobalNums, setAyahGlobalNums] = useState([]);
  const [loading, setLoading] = useState(false);
  const [curAyahIdx, setCurAyahIdx] = useState(0);
  const [reps, setReps] = useState(0);
  const [goals, setGoals] = useState(0);
  const [totalC, setTotalC] = useState(0);
  const [totalQ, setTotalQ] = useState(0);
  const [exType, setExType] = useState("listen");
  const [showGoal, setShowGoal] = useState(false);

  const curAyah = ayahs[curAyahIdx] || "";
  const curGlobalNum = ayahGlobalNums[curAyahIdx] || 0;
  const totalAyahs = ayahs.length;

  // Fetch surah — use embedded data (Juz 30 + Fatiha), fallback to API for others
  const [fetchError, setFetchError] = useState("");

  const fetchSurah = async (num, from, to) => {
    setLoading(true);
    setFetchError("");
    let fetched = false;
    
    // Check embedded data first
    if (QURAN_DATA[num]) {
      const allV = QURAN_DATA[num].v;
      const selected = allV.slice(from - 1, to);
      if (selected.length > 0) {
        setAyahs(selected.map(a => a[0]));
        setAyahGlobalNums(selected.map(a => a[1]));
        fetched = true;
      }
    }
    
    // Fallback to API for surahs not embedded
    if (!fetched) {
      try {
        const controller = new AbortController();
        const timeout = setTimeout(() => controller.abort(), 8000);
        const res = await fetch(`https://api.alquran.cloud/v1/surah/${num}`, { signal: controller.signal });
        clearTimeout(timeout);
        const json = await res.json();
        if (json.code === 200 && json.data && json.data.ayahs) {
          const selected = json.data.ayahs.slice(from - 1, to);
          if (selected.length > 0) {
            setAyahs(selected.map(a => a.text));
            setAyahGlobalNums(selected.map(a => a.number));
            fetched = true;
          }
        }
      } catch (e) {
        console.error("API error:", e);
      }
    }
    
    if (!fetched) {
      setFetchError("هذه السورة غير متوفرة حالياً بدون إنترنت. جرّب سور جزء عمّ أو الفاتحة.");
    }
    setLoading(false);
    return fetched;
  };

  const startMatch = async () => {
    const ok = await fetchSurah(surahNum, ayFrom, ayTo);
    if (!ok) return;
    setCurAyahIdx(0); setReps(0); setGoals(0);
    setTotalC(0); setTotalQ(0); setShowGoal(false);
    setExType("listen");
    sfx("whistle");
    setView("match");
  };

  const onExDone = (c, q) => {
    setTotalC(tc => tc + c); setTotalQ(tq => tq + q);
    const next = reps + 1;
    setReps(next);
    if (next >= REPS) {
      sfx("goal"); setShowGoal(true); setGoals(g => g + 1);
      setTimeout(() => {
        setShowGoal(false);
        if (curAyahIdx + 1 >= totalAyahs) { setView("result"); }
        else { setCurAyahIdx(i => i + 1); setReps(0); setExType("listen"); }
      }, 5000);
    } else {
      setExType(getExType(next));
    }
  };

  useEffect(() => { const s = document.createElement("style"); s.textContent = CSS; document.head.appendChild(s); return () => s.remove(); }, []);

  const base = { fontFamily: "'Tajawal',sans-serif", minHeight: "100vh", color: "#1a1a2e", overflow: "hidden" };

  // ── WELCOME ──
  if (view === "welcome") return (
    <div style={{ ...base, background: "linear-gradient(150deg, #0D7C3D 0%, #1B5E20 50%, #0A3D1F 100%)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", textAlign: "center", padding: 24 }}>
      <div style={{ position: "absolute", top: -60, right: "10%", width: 240, height: 240, borderRadius: "50%", background: "radial-gradient(circle,rgba(249,168,37,0.1),transparent 70%)", pointerEvents: "none" }} />
      <div style={{ animation: "pop 0.6s both", fontSize: 72, marginBottom: 10 }}>⚽</div>
      <h1 style={{ fontFamily: "'Tajawal',sans-serif", fontWeight: 900, fontSize: 54, color: "#fff", animation: "fadeUp 0.5s 0.1s both", textShadow: "0 3px 20px rgba(0,0,0,0.2)" }}>مِقدام</h1>
      <p style={{ fontSize: 17, color: "rgba(255,255,255,0.7)", animation: "fadeUp 0.5s 0.25s both", marginBottom: 44, maxWidth: 260 }}>حوّل حفظ القرآن إلى مباراة حماسية!</p>
      <div style={{ animation: "fadeUp 0.5s 0.4s both" }}>
        <Btn onClick={() => setView("setup")} color="#F9A825" style={{ fontSize: 20, padding: "16px 44px" }}>🏟️ ابدأ المغامرة</Btn>
      </div>
    </div>
  );

  // ── SETUP ──
  if (view === "setup") {
    const views = [
      <div key="0" style={{ animation: "fadeUp 0.3s both", textAlign: "center" }}>
        <div style={{ fontSize: 44, marginBottom: 10 }}>⚽</div>
        <h2 style={{ fontSize: 21, marginBottom: 10 }}>اسم اللاعب</h2>
        <input value={pName} onChange={e => setPName(e.target.value)} placeholder="مثال: سلطان" style={{ width: "100%", maxWidth: 260, padding: "12px 18px", fontSize: 20, borderRadius: 14, border: "3px solid #0D7C3D", outline: "none", textAlign: "center", fontFamily: "'Tajawal'", direction: "rtl" }} />
      </div>,
      <div key="1" style={{ animation: "fadeUp 0.3s both", textAlign: "center" }}>
        <div style={{ fontSize: 44, marginBottom: 10 }}>🏟️</div>
        <h2 style={{ fontSize: 21, marginBottom: 10 }}>اسم الفريق</h2>
        <input value={tName} onChange={e => setTName(e.target.value)} placeholder="مثال: النسور" style={{ width: "100%", maxWidth: 260, padding: "12px 18px", fontSize: 20, borderRadius: 14, border: "3px solid #0D7C3D", outline: "none", textAlign: "center", fontFamily: "'Tajawal'", direction: "rtl" }} />
      </div>,
      <div key="2" style={{ animation: "fadeUp 0.3s both", textAlign: "center" }}>
        <Jersey c={JERSEY_COLORS[jCol]} n={jNum} sz={90} />
        <h2 style={{ fontSize: 19, margin: "8px 0 12px" }}>اختر قميصك</h2>
        <div style={{ display: "flex", gap: 7, justifyContent: "center", flexWrap: "wrap", marginBottom: 12 }}>
          {JERSEY_COLORS.map((c, i) => <div key={i} onClick={() => { sfx("tap"); setJCol(i); }} style={{ width: 38, height: 38, borderRadius: 11, background: c.p, cursor: "pointer", border: jCol === i ? "3px solid #F9A825" : "3px solid transparent", boxShadow: jCol === i ? "0 0 10px rgba(249,168,37,0.4)" : "none", transition: "all 0.2s" }} />)}
        </div>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 12 }}>
          <Btn onClick={() => setJNum(Math.max(1, jNum - 1))} color="#5a5a6a" style={{ padding: "7px 15px" }}>-</Btn>
          <span style={{ fontSize: 28, fontWeight: 900, minWidth: 40, textAlign: "center" }}>{jNum}</span>
          <Btn onClick={() => setJNum(Math.min(99, jNum + 1))} color="#5a5a6a" style={{ padding: "7px 15px" }}>+</Btn>
        </div>
      </div>,
      <div key="3" style={{ animation: "fadeUp 0.3s both", textAlign: "center" }}>
        <div style={{ fontSize: 52, marginBottom: 6 }}>{BADGES[bdg]}</div>
        <h2 style={{ fontSize: 19, marginBottom: 12 }}>شعار فريقك</h2>
        <div style={{ display: "flex", gap: 9, justifyContent: "center", flexWrap: "wrap" }}>
          {BADGES.map((b, i) => <div key={i} onClick={() => { sfx("tap"); setBdg(i); }} style={{ fontSize: 30, padding: 7, borderRadius: 12, cursor: "pointer", background: bdg === i ? "#FFF8E1" : "#F5F5F0", border: bdg === i ? "3px solid #F9A825" : "3px solid transparent", transition: "all 0.2s" }}>{b}</div>)}
        </div>
      </div>,
    ];
    const ok = setupStep === 0 ? pName.length > 0 : setupStep === 1 ? tName.length > 0 : true;
    const done = () => { setProfile({ name: pName, team: tName, num: jNum, color: JERSEY_COLORS[jCol], badge: BADGES[bdg] }); setView("pick"); };

    return (
      <div style={{ ...base, background: "#fff", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 24 }}>
        <div style={{ display: "flex", gap: 5, marginBottom: 26 }}>
          {[0,1,2,3].map(i => <div key={i} style={{ width: i === setupStep ? 26 : 7, height: 7, borderRadius: 4, background: i <= setupStep ? "#0D7C3D" : "#ddd", transition: "all 0.3s" }} />)}
        </div>
        {views[setupStep]}
        <div style={{ marginTop: 26, display: "flex", gap: 10 }}>
          {setupStep > 0 && <Btn onClick={() => setSetupStep(s => s - 1)} color="#5a5a6a">رجوع</Btn>}
          {setupStep < 3 ? <Btn onClick={() => setSetupStep(s => s + 1)} disabled={!ok}>التالي ←</Btn> : <Btn onClick={done} color="#F9A825" style={{ fontSize: 18, padding: "14px 34px" }}>🏟️ انطلق!</Btn>}
        </div>
      </div>
    );
  }

  // ── PICK SURAH ──
  if (view === "pick") {
    const maxAy = SURAH_AYAH_COUNT[surahNum - 1] || 7;
    return (
      <div style={{ ...base, background: "linear-gradient(180deg,#E8F5E9,#C8E6C9)", display: "flex", flexDirection: "column", padding: 20 }}>
        {profile && (
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 18, animation: "fadeUp 0.3s both" }}>
            <Jersey c={profile.color} n={profile.num} sz={44} />
            <div><div style={{ fontWeight: 800, fontSize: 16 }}>{profile.name}</div><div style={{ fontSize: 12, color: "#5a5a6a" }}>{profile.badge} {profile.team}</div></div>
          </div>
        )}
        <div style={{ background: "#fff", borderRadius: 24, padding: 22, boxShadow: "0 4px 20px rgba(0,0,0,0.05)", animation: "fadeUp 0.35s 0.08s both", flex: 1 }}>
          <h2 style={{ fontSize: 21, fontWeight: 800, marginBottom: 18, textAlign: "center" }}>📖 اختر مباراة اليوم</h2>
          <label style={{ display: "block", fontSize: 13, fontWeight: 700, color: "#5a5a6a", marginBottom: 5 }}>السورة</label>
          <select value={surahNum} onChange={e => { const v = +e.target.value; setSurahNum(v); setAyFrom(1); setAyTo(SURAH_AYAH_COUNT[v - 1]); }}
            style={{ width: "100%", padding: "11px 14px", borderRadius: 14, border: "2px solid #e0e0e0", fontSize: 17, fontFamily: "'Tajawal'", marginBottom: 16, direction: "rtl", background: "#fff" }}>
            {SURAH_NAMES.map((n, i) => <option key={i} value={i + 1}>{i + 1}. {n}</option>)}
          </select>
          <div style={{ display: "flex", gap: 12, marginBottom: 16 }}>
            <div style={{ flex: 1 }}>
              <label style={{ display: "block", fontSize: 13, fontWeight: 700, color: "#5a5a6a", marginBottom: 5 }}>من آية</label>
              <input type="number" value={ayFrom} min={1} max={ayTo} onChange={e => setAyFrom(Math.max(1, Math.min(+e.target.value, ayTo)))}
                style={{ width: "100%", padding: 11, borderRadius: 14, border: "2px solid #e0e0e0", fontSize: 17, textAlign: "center", fontFamily: "'Tajawal'" }} />
            </div>
            <div style={{ flex: 1 }}>
              <label style={{ display: "block", fontSize: 13, fontWeight: 700, color: "#5a5a6a", marginBottom: 5 }}>إلى آية</label>
              <input type="number" value={ayTo} min={ayFrom} max={maxAy} onChange={e => setAyTo(Math.max(ayFrom, Math.min(+e.target.value, maxAy)))}
                style={{ width: "100%", padding: 11, borderRadius: 14, border: "2px solid #e0e0e0", fontSize: 17, textAlign: "center", fontFamily: "'Tajawal'" }} />
            </div>
          </div>
          <div style={{ background: "#E8F5E9", borderRadius: 14, padding: 13, marginBottom: 18, direction: "rtl" }}>
            <p style={{ fontSize: 14, color: "#0A5C2D" }}>🏟️ <b>المباراة:</b> سورة {SURAH_NAMES[surahNum - 1]} — الآيات {ayFrom} إلى {ayTo}</p>
            <p style={{ fontSize: 13, color: "#0A5C2D", marginTop: 4 }}>⚽ <b>{ayTo - ayFrom + 1} هجمة</b> × 30 تكرار لكل آية</p>
          </div>
          {fetchError && (
            <div style={{ background: "#FFEBEE", borderRadius: 14, padding: 13, marginBottom: 14, direction: "rtl" }}>
              <p style={{ fontSize: 14, color: "#C62828" }}>⚠️ {fetchError}</p>
            </div>
          )}
          <Btn onClick={startMatch} color="#0D7C3D" full disabled={loading}
            style={{ fontSize: 19, padding: 15, animation: loading ? "none" : "pulse 2.5s infinite" }}>
            {loading ? "⏳ جاري التحميل..." : "⚽ انطلق للمباراة!"}
          </Btn>
        </div>
      </div>
    );
  }

  // ── GOAL CELEBRATION (5 seconds, epic) ──
  if (view === "match" && showGoal) return (
    <div style={{ ...base, background: "radial-gradient(ellipse at center, #1B5E20 0%, #0A3D1F 50%, #071a0e 100%)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", textAlign: "center", padding: 24 }}>
      <Confetti />
      {/* Glowing circle behind */}
      <div style={{ position: "absolute", width: 300, height: 300, borderRadius: "50%", background: "radial-gradient(circle, rgba(249,168,37,0.25), transparent 70%)", animation: "pulse 1.5s infinite" }} />
      <div style={{ animation: "goalZoom 0.9s both", zIndex: 10 }}>
        <div style={{ fontSize: 90, marginBottom: 4, filter: "drop-shadow(0 4px 20px rgba(0,0,0,0.3))" }}>⚽</div>
        <h1 style={{ fontFamily: "'Tajawal',sans-serif", fontWeight: 900, fontSize: 72, color: "#F9A825", animation: "goalGlow 1.5s infinite", margin: "8px 0" }}>هـــدف!</h1>
        <p style={{ fontSize: 28, color: "rgba(255,255,255,0.9)", fontWeight: 800, animation: "fadeUp 0.5s 0.4s both" }}>GOOOAAL!</p>
      </div>
      <div style={{ animation: "fadeUp 0.6s 0.7s both", marginTop: 20, zIndex: 10 }}>
        {profile && <Jersey c={profile.color} n={profile.num} sz={90} />}
        <p style={{ color: "rgba(255,255,255,0.85)", fontSize: 20, marginTop: 8, fontWeight: 700 }}>{profile?.name} يسجّل! 🎉</p>
      </div>
      <div style={{ animation: "pop 0.5s 1s both", marginTop: 16, background: "rgba(0,0,0,0.4)", borderRadius: 16, padding: "10px 28px", zIndex: 10 }}>
        <span style={{ color: "#fff", fontWeight: 900, fontSize: 36 }}>{goals + 1}</span>
        <span style={{ color: "rgba(255,255,255,0.5)", fontSize: 24, margin: "0 8px" }}>-</span>
        <span style={{ color: "rgba(255,255,255,0.5)", fontSize: 28 }}>0</span>
      </div>
    </div>
  );

  // ── MATCH ──
  if (view === "match" && ayahs.length > 0) {
    const info = EX_LABELS[exType] || EX_LABELS.listen;
    return (
      <div style={{ ...base, background: "linear-gradient(180deg,#E8F5E9,#C8E6C9)", display: "flex", flexDirection: "column" }}>
        {/* Header */}
        <div style={{ padding: "10px 16px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 5 }}>
            <span style={{ fontSize: 18 }}>⚽</span>
            <span style={{ fontWeight: 900, fontSize: 17, color: "#0D7C3D" }}>{goals}</span>
            <span style={{ fontSize: 13, color: "#999" }}>- 0</span>
          </div>
          <div style={{ fontSize: 12, color: "#5a5a6a", fontWeight: 600 }}>آية {curAyahIdx + 1} / {totalAyahs}</div>
          <div style={{ fontSize: 12, color: "#5a5a6a", background: "rgba(0,0,0,0.05)", padding: "3px 10px", borderRadius: 8 }}>
            تكرار {reps} / {REPS}
          </div>
        </div>

        {/* Pitch */}
        <div style={{ padding: "0 10px" }}>
          <Pitch progress={reps} maxReps={REPS} scored={false} goalAnim={false} jerseyColor={profile?.color} />
        </div>

        {/* Exercise badge */}
        <div style={{ textAlign: "center", margin: "8px 0 4px" }}>
          <span style={{ background: info.color, color: "#fff", padding: "3px 13px", borderRadius: 20, fontSize: 13, fontWeight: 700 }}>
            {info.icon} {info.label}
          </span>
        </div>

        {/* Exercise */}
        <div style={{ flex: 1, padding: "6px 16px 20px", overflowY: "auto" }}>
          {exType === "listen" && <ExListen key={`l${curAyahIdx}-${reps}`} ayah={curAyah} ayahGlobalNum={curGlobalNum} onDone={onExDone} />}
          {exType === "nextWord" && <ExNextWord key={`n${curAyahIdx}-${reps}`} ayah={curAyah} allAyahs={ayahs} onDone={onExDone} />}
          {exType === "blanks" && <ExBlanks key={`b${curAyahIdx}-${reps}`} ayah={curAyah} allAyahs={ayahs} onDone={onExDone} />}
          {exType === "order" && <ExOrder key={`o${curAyahIdx}-${reps}`} ayah={curAyah} onDone={onExDone} />}
        </div>
      </div>
    );
  }

  // ── RESULT ──
  if (view === "result") {
    const acc = totalQ > 0 ? Math.round((totalC / totalQ) * 100) : 100;
    const stars = acc >= 90 ? 3 : acc >= 70 ? 2 : 1;
    return (
      <div style={{ ...base, background: "linear-gradient(180deg,#1a1a2e,#0d1b3e)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 24, textAlign: "center" }}>
        <div style={{ animation: "fadeUp 0.3s both" }}>
          <div style={{ fontSize: 12, color: "rgba(255,255,255,0.35)", letterSpacing: 3, marginBottom: 10 }}>نهاية المباراة</div>
        </div>
        <div style={{ display: "flex", gap: 7, margin: "16px 0", justifyContent: "center" }}>
          {[0,1,2].map(i => <span key={i} style={{ fontSize: 38, animation: i < stars ? `starSpin 0.5s ${i * 0.2}s both` : "none", filter: i < stars ? "none" : "grayscale(1) opacity(0.15)" }}>⭐</span>)}
        </div>
        <div style={{ background: "rgba(255,255,255,0.06)", borderRadius: 20, padding: 20, width: "100%", maxWidth: 310, animation: "fadeUp 0.35s 0.15s both", border: "1px solid rgba(255,255,255,0.06)", marginBottom: 18 }}>
          <div style={{ fontSize: 44, fontWeight: 900, color: "#fff", marginBottom: 2 }}>{goals} - 0</div>
          <div style={{ fontSize: 13, color: "rgba(255,255,255,0.4)" }}>سورة {SURAH_NAMES[surahNum - 1]}</div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginTop: 14 }}>
            {[["🎯", `${acc}%`, "دقة"],["✅", `${totalC}`, "صحيحة"]].map(([ic, v, l], i) => (
              <div key={i}><div style={{ fontSize: 20 }}>{ic}</div><div style={{ color: "#fff", fontSize: 20, fontWeight: 800 }}>{v}</div><div style={{ color: "rgba(255,255,255,0.35)", fontSize: 11 }}>{l}</div></div>
            ))}
          </div>
        </div>
        <div style={{ animation: "fadeUp 0.35s 0.3s both", background: "linear-gradient(135deg,#F9A825,#FFB300)", borderRadius: 16, padding: 13, width: "100%", maxWidth: 310, marginBottom: 18 }}>
          <p style={{ fontSize: 17, fontWeight: 800, color: "#1a1a2e" }}>{stars === 3 ? "🌟 أداء أسطوري!" : stars === 2 ? "💪 أداء رائع!" : "👍 أحسنت!"}</p>
        </div>
        <div style={{ display: "flex", gap: 10, animation: "fadeUp 0.35s 0.45s both" }}>
          <Btn onClick={() => setView("pick")} color="rgba(255,255,255,0.1)" style={{ border: "1px solid rgba(255,255,255,0.12)", boxShadow: "none" }}>📖 مباراة جديدة</Btn>
          <Btn onClick={startMatch} color="#0D7C3D">⚽ إعادة</Btn>
        </div>
      </div>
    );
  }

  return null;
}
